import boto3

def lambda_handler(event, context):
    # Example function logic
    s3 = boto3.client('s3')
    dynamodb = boto3.resource('dynamodb')
    sns = boto3.client('sns')
    sqs = boto3.client('sqs')

    # Perform operations using the shared permissions
    response = s3.get_object(Bucket='your-bucket', Key='your-key')
    table = dynamodb.Table('your-table')
    table.put_item(Item={'key': 'value'})
    sns.publish(TopicArn='your-sns-topic-arn', Message='Hello, World!')
    sqs.send_message(QueueUrl='your-sqs-queue-url', MessageBody='Hello, World!')

    return {
        'statusCode': 200,
        'body': 'Function executed successfully'
    }